import 'package:flutter/material.dart';import '../../../../../Core/Utils/constant.dart';import '../../../../../Core/Utils/text_style.dart';class DetailsTheBook extends StatefulWidget {  const DetailsTheBook({super.key});  @override  State<DetailsTheBook> createState() => _DetailsTheBookState();}class _DetailsTheBookState extends State<DetailsTheBook>    with SingleTickerProviderStateMixin {  late AnimationController _controller;  late Animation<double> _animation;  @override  void initState() {    super.initState();    _controller = AnimationController(      duration: const Duration(seconds: 2),      vsync: this,    )..repeat(reverse: true);    _animation = Tween<double>(begin: 0, end: 20).animate(      CurvedAnimation(parent: _controller, curve: Curves.easeInOut),    );  }  @override  void dispose() {    _controller.dispose();    super.dispose();  }  @override  Widget build(BuildContext context) {    return Padding(      padding: const EdgeInsets.only(top: 10, right: 100, left: 100),      child: AnimatedBuilder(        animation: _animation,        builder: (context, child) {          return Column(            mainAxisAlignment: MainAxisAlignment.center,            children: [              SizedBox(                height: MediaQuery.of(context).size.height * .30,                child: AspectRatio(                  aspectRatio: 162 / 243,                  child: Transform.translate(                    offset: Offset(0, _animation.value),                    child: Container(                      color: Colors.amber,                    ),                  ),                ),              ),              const SizedBox(height: 30),              Transform.translate(                offset: Offset(0, _animation.value),                child: const Text(                  'Harry Potter and the Goblet of Fire',                  style: Styles.textStyle30,                  maxLines: 3,                  textAlign: TextAlign.center,                ),              ),              Transform.translate(                offset: Offset(0, _animation.value),                child: Text(                  'Name Auth',                  style: Styles.textStyle18.copyWith(color: const Color(0xffc4c1c1)),                ),              ),              const SizedBox(height: 10),              Transform.translate(                offset: Offset(0, _animation.value),                child: Row(                  mainAxisAlignment: MainAxisAlignment.center,                  children: [                    AppIcons.starOfRating,                    Text(                      "4.8",                      style: Styles.textStyle14.copyWith(color: Colors.white),                    ),                    const SizedBox(width: 5),                    Text(                      "(2390)",                      style: Styles.textStyle14.copyWith(color: const Color(0xff707070)),                    ),                  ],                ),              )            ],          );        },      ),    );  }}